'use strict';

// MODULES //

import stride2offset from '@stdlib/strided-base-stride2offset';
import ndarray from './ndarray.js';


// MAIN //

/**
* Multiplies a double-precision complex floating-point strided array `x` by a constant and adds the result to a double-precision complex floating-point strided array `y` multiplied by a constant.
*
* @param {PositiveInteger} N - number of indexed elements
* @param {Complex128} alpha - first scalar constant
* @param {Complex128Array} x - input array
* @param {integer} strideX - `x` stride length
* @param {Complex128} beta - second scalar constant
* @param {Complex128Array} y - output array
* @param {integer} strideY - `y` stride length
* @returns {Complex128Array} output array
*
* @example
* import Complex128Array from '@stdlib/array-complex128';
* import Complex128 from '@stdlib/complex-float64-ctor';
*
* var x = new Complex128Array( [ 1.0, 2.0, 3.0, -1.0, 0.0, 1.0 ] );
* var y = new Complex128Array( [ 2.0, 1.0, -1.0, 3.0, 4.0, 0.0 ] );
*
* var alpha = new Complex128( 2.0, 1.0 );
* var beta = new Complex128( 1.0, -1.0 );
*
* zaxpby( x.length, alpha, x, 1, beta, y, 1 );
* // y => <Complex128Array>[ 3.0, 4.0, 9.0, 5.0, 3.0, -2.0 ]
*/
function zaxpby( N, alpha, x, strideX, beta, y, strideY ) {
	return ndarray( N, alpha, x, strideX, stride2offset( N, strideX ), beta, y, strideY, stride2offset( N, strideY ) ); // eslint-disable-line max-len
}


// EXPORTS //

export default zaxpby;
